INSERT INTO `projects` (`id`, `title`, `description`, `link`, `link2`, `skill_ids`, `photo`, `date_created`) VALUES
(1, 'Designing a User-Centered Laundry Monitoring and Services System for Walk-In Laundry Shops', 'A user-centered design study proposing a laundry monitoring and services system for local walk-in laundry shops in the Philippines, covering user research, task analysis, and interface design based on ISO 9241-11 usability criteria.', 'https://drive.google.com/file/d/19F2XNvYh6aSGEzcMiV6kIGMPBPBreK-q/view?usp=sharing', 'https://www.figma.com/design/WnDCUOoRGCss4WZB9ttaLG/A%C3%B1ora---Final-Prototype--Copy-?node-id=36-1089&t=ScGHWWX3LDmlgslC-1', '15', 'Screenshot 2026-03-16 113409.png', '2026-03-16'),
(3, 'Mekaniko — Mechanic Shop Appointment System', 'A static multi-page mechanic shop website featuring a service booking form, admin dashboard, and contact page. Built with HTML, CSS, Bootstrap, and vanilla JavaScript.', 'https://github.com/ariabytes/practice1-mekaniko', '', '7,5,21,4', 'Screenshot 2026-03-16 133109.png', '2026-02-12'),
(4, 'La Lavandera — Laundry Monitoring and Services System', 'A desktop application built with Python and PyQt6 for managing laundry shop operations. Features order management, payment tracking, customer management, and real-time order status monitoring. Demonstrates OOP principles — encapsulation, inheritance, polymorphism, and abstraction.', 'https://github.com/ariabytes/laundry-management-and-services-system', '', '3,2', '501353845-f42a8b08-3c53-4f3e-b73a-af8a66b89dec.png', '2025-10-15'),
(5, 'Library Management System', 'A Java-based library management system built for a Data Structures and Algorithms course. Features book and member management, borrowing/returning, reservation queues, and role-based access for users and librarians. Implements core DSA concepts including HashMap, PriorityQueue (max-heap), LinkedList, binary search, bubble sort, and insertion sort. Built with Java Swing GUI and flat-file persistence.', 'https://github.com/ariabytes/library-management-system-with-book-borrowing', '', '1', 'Screenshot 2026-03-16 133833.png', '2025-09-21'),
(6, 'LiBorrower — Library Borrowing Records System', 'A front-end library borrowing records system built for the 1st Laboratory Exam of IT 9a — Professional Track for IT 3. Features login with a 5-attempt limit, dynamic navbar via fetch(), admin dashboard with time-based greeting, and a borrowing form that stores and displays records in real-time using JavaScript arrays and objects.', 'https://github.com/ariabytes/IT9a-LabExam1', '', '7,5,21,4', 'Screenshot 2026-03-16 140326.png', '2026-02-20'),
(7, 'Web-Based Portfolio Management System', 'A dynamic database-driven portfolio website built with PHP and MySQL for IT 9a — Professional Track for IT 3. Features a public portfolio view and a secure admin panel for managing projects, skills, certifications, and education history. Implements CRUD operations, session-based authentication, LONGBLOB image storage, file upload handling, and a responsive design.', 'https://github.com/ariabytes/IT9a-MiniProject-Portfolio', '', '7,5,21,4,3,6', 'Screenshot 2026-03-16 141152.png', '2026-02-25'),
(8, 'Pet Adoption System', 'A practice PHP and MySQL CRUD system for managing pet adoptions. Features pet listings with LONGBLOB image storage, category management, adoption status tracking, and a public-facing available pets view.', 'https://github.com/ariabytes/PetAdoption-Practice', '', '7,21,3,6', 'Screenshot 2026-03-16 142152.png', '2026-03-12');

